import { Test, TestingModule } from '@nestjs/testing';

import { CorrelationIdMiddleware } from '@middlewares/correlation-id.middleware';

const mockCorrelator = {
	withId: jest.fn(),
};

jest.mock('correlation-id-ts', () => ({
	correlator: mockCorrelator,
}));

const mockRandomUUID = jest.fn();

jest.mock('node:crypto', () => ({
	randomUUID: () => mockRandomUUID(),
}));

function createMockReq(headers: Record<string, string> = {}): { headers: Record<string, string> } {
	return { headers };
}

describe('CorrelationIdMiddleware', () => {
	let middleware: CorrelationIdMiddleware;

	beforeEach(async () => {
		mockCorrelator.withId.mockImplementation(({ fn }: { fn: () => void }) => fn());

		const module: TestingModule = await Test.createTestingModule({
			providers: [CorrelationIdMiddleware],
		}).compile();

		middleware = module.get<CorrelationIdMiddleware>(CorrelationIdMiddleware);
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(middleware).toBeDefined();
	});

	describe('use', () => {
		it('should use the correlation ID from the request header when present', () => {
			const req = createMockReq({ 'x-correlation-id': 'header-id-123' });
			const next = jest.fn();

			middleware.use(req as any, {} as any, next);

			expect(mockCorrelator.withId).toHaveBeenCalledWith({
				correlationId: 'header-id-123',
				fn: expect.any(Function),
			});
		});

		it('should generate a UUID when no correlation ID header is present', () => {
			mockRandomUUID.mockReturnValue('generated-uuid-456');
			const req = createMockReq({});
			const next = jest.fn();

			middleware.use(req as any, {} as any, next);

			expect(mockCorrelator.withId).toHaveBeenCalledWith({
				correlationId: 'generated-uuid-456',
				fn: expect.any(Function),
			});
		});

		it('should not call randomUUID when correlation ID header is present', () => {
			const req = createMockReq({ 'x-correlation-id': 'existing-id' });
			const next = jest.fn();

			middleware.use(req as any, {} as any, next);

			expect(mockRandomUUID).not.toHaveBeenCalled();
		});

		it('should call next() inside the correlator.withId fn', () => {
			const req = createMockReq({ 'x-correlation-id': 'some-id' });
			const next = jest.fn();

			middleware.use(req as any, {} as any, next);

			expect(next).toHaveBeenCalledTimes(1);
		});

		it('should pass next() to correlator.withId fn and invoke it when fn is called', () => {
			mockCorrelator.withId.mockImplementation(({ fn }: { fn: () => void }) => {
				fn();
			});
			const req = createMockReq({ 'x-correlation-id': 'some-id' });
			const next = jest.fn();

			middleware.use(req as any, {} as any, next);

			expect(next).toHaveBeenCalledTimes(1);
		});

		it('should not call next() when correlator.withId does not invoke fn', () => {
			mockCorrelator.withId.mockImplementation(() => {});
			const req = createMockReq({ 'x-correlation-id': 'some-id' });
			const next = jest.fn();

			middleware.use(req as any, {} as any, next);

			expect(next).not.toHaveBeenCalled();
		});
	});
});

